function solve(nums: number[]): number {
    const n = nums.length;
    if (n === 0) return 0;

    const sieve = new Array(n).fill(true);
    sieve[0] = false;
    sieve[1] = false;
    for (let i = 2; i * i < n; i++) {
        if (sieve[i]) {
            for (let j = i * i; j < n; j += i) {
                sieve[j] = false;
            }
        }
    }

    let sumA = 0;
    let sumB = 0;
    for (let i = 0; i < n; i++) {
        if (sieve[i]) {
            sumA += nums[i];
        } else {
            sumB += nums[i];
        }
    }

    return Math.abs(sumA - sumB);
}

